import re

_NUMBER_RE = re.compile(r"\d+\.\d*|\.\d+|\d+")


def _tokenize(expr):
    tokens = []
    i, n = 0, len(expr)
    while i < n:
        c = expr[i]
        if c.isspace():
            i += 1
        elif c.isdigit() or c == ".":
            m = _NUMBER_RE.match(expr, i)
            if m is None:
                raise ValueError(f"invalid number at position {i}")
            tokens.append(("num", float(m.group())))
            i = m.end()
        elif expr.startswith("**", i):
            tokens.append(("op", "**"))
            i += 2
        elif c in "+-*/()":
            tokens.append(("op", c))
            i += 1
        else:
            raise ValueError(f"illegal character {c!r} at position {i}")
    return tokens


class _Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def _peek(self):
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def _next(self):
        tok = self._peek()
        if tok is None:
            raise ValueError("unexpected end of expression")
        self.pos += 1
        return tok

    def expression(self):
        value = self.term()
        while True:
            tok = self._peek()
            if tok is not None and tok[0] == "op" and tok[1] in ("+", "-"):
                self.pos += 1
                right = self.term()
                value = value + right if tok[1] == "+" else value - right
            else:
                return value

    def term(self):
        value = self.factor()
        while True:
            tok = self._peek()
            if tok is not None and tok[0] == "op" and tok[1] in ("*", "/"):
                self.pos += 1
                right = self.factor()
                value = value * right if tok[1] == "*" else value / right
            else:
                return value

    def factor(self):
        # unary minus binds looser than **, so -2**2 == -(2**2)
        if self._peek() == ("op", "-"):
            self.pos += 1
            return -self.factor()
        return self.power()

    def power(self):
        base = self.primary()
        if self._peek() == ("op", "**"):
            self.pos += 1
            # right-associative; exponent may itself carry a unary minus
            exponent = self.factor()
            result = base ** exponent
            if isinstance(result, complex):
                raise ValueError("expression produced a complex result")
            return result
        return base

    def primary(self):
        kind, val = self._next()
        if kind == "num":
            return val
        if val == "(":
            value = self.expression()
            if self._next() != ("op", ")"):
                raise ValueError("expected closing parenthesis")
            return value
        raise ValueError(f"unexpected token {val!r}")


def evaluate(expr: str) -> float:
    tokens = _tokenize(expr)
    parser = _Parser(tokens)
    value = parser.expression()
    if parser.pos != len(tokens):
        extra = tokens[parser.pos]
        raise ValueError(f"unexpected token {extra[1]!r}")
    return float(value)
